#!/usr/bin/env python3
"""
投研情报汇聚脚本 v2
修复版：真实接入微博监控、信号CSV、持仓快照，输出结构化情报
"""

import json, re, sys, html as html_module
from pathlib import Path
from datetime import datetime, date, timedelta
from typing import Optional
import csv

import argparse, hashlib
from real_holdings_source import resolve_real_holdings

# ── 路径常量 ──────────────────────────────────────────────
WORKSPACE      = Path.home() / ".openclaw" / "workspace"
QUANT_ROOT     = WORKSPACE / "quant_projects" / "personal-a-share-research-system"
TREND_DIR      = WORKSPACE / "other_projects" / "TrendRadar"
WEIBO_DIR      = WORKSPACE / "skills" / "weibo-monitor"
WEIBO_SKILL    = WEIBO_DIR / "SKILL.md"
WEIBO_LOG      = WEIBO_DIR / "logs" / "weibo_monitor.log"
FEISHU_WEBHOOK = "https://open.feishu.cn/open-apis/bot/v2/hook/f54d31a7-226d-4fac-aeaf-44b84c5c85b7"
OUTPUT_DIR     = WORKSPACE / "research" / "reports"

today = date.today()
today_str   = today.strftime("%Y-%m-%d")
today_short = today.strftime("%Y%m%d")

# A股名称缓存（手工补充 + 本地基础表自动加载）
STOCK_NAMES: dict[str, str] = {
    "002715": "登云股份", "002316": "亚联发展", "002188": "中天服务",
    "603629": "利通电子", "002802": "洪汇新材", "002817": "黄山胶囊",
    "002820": "桂发祥", "002963": "豪尔赛", "003003": "天元股份",
    "002920": "德赛西威", "002830": "名雕股份", "300500": "启迪设计",
    "600493": "凤竹纺织", "002888": "惠威科技", "002719": "麦趣尔",
    "002471": "上海莱士", "002565": "上海三毛", "002865": "钱江生化",
    "300189": "神农科技", "300342": "天银机电", "300444": "杭电股份",
    "300672": "国科微",   "300900": "广联航空", "688387": "兴通股份",
    "688568": "龙腾光电", "688766": "普冉股份", "002025": "航天电器",
    "002240": "威华股份", "002151": "北斗星通", "002173": "创新医疗",
    "600363": "联创光电", "688322": "奥比中光", "301333": "诺思格",
    "300622": "博士眼镜", "300829": "金丹科技", "06969": "联想集团",
    "09988": "阿里巴巴",  "588000": "科创50ETF",
}

NAME_SOURCE_FILES = [
    WORKSPACE / "data" / "a_stock_list.csv",
    WORKSPACE / "quant_projects" / "quant_system" / "data" / "stock_basic.csv",
]

STOCK_NAME_CACHE: Optional[dict[str, str]] = None


def _code_variants(code: str) -> list[str]:
    """生成代码的多种匹配形态，兼容 ts_code / 纯数字 / 港股前导零。"""
    raw = (code or "").strip().upper()
    if not raw:
        return []

    bare = raw.replace(".SH", "").replace(".SZ", "").replace(".HK", "")
    variants: list[str] = []
    for item in (raw, bare):
        if item and item not in variants:
            variants.append(item)

    if bare.isdigit():
        padded = bare.zfill(6)
        if padded not in variants:
            variants.append(padded)
        if raw.endswith(".SH") and f"{padded}.SH" not in variants:
            variants.append(f"{padded}.SH")
        if raw.endswith(".SZ") and f"{padded}.SZ" not in variants:
            variants.append(f"{padded}.SZ")
        if raw.endswith(".HK") and f"{padded}.HK" not in variants:
            variants.append(f"{padded}.HK")
    return variants


def _load_stock_name_cache() -> dict[str, str]:
    cache: dict[str, str] = {}

    # 先加载本地基础表，优先相信自动同步的最新证券主数据。
    for csv_path in NAME_SOURCE_FILES:
        if not csv_path.exists():
            continue
        try:
            with csv_path.open(encoding="utf-8-sig", newline="") as f:
                reader = csv.DictReader(f)
                for row in reader:
                    name = (row.get("name") or row.get("股票名称") or row.get("证券名称") or "").strip()
                    if not name:
                        continue
                    for key in (
                        row.get("ts_code", ""),
                        row.get("symbol", ""),
                        row.get("code", ""),
                        row.get("证券代码", ""),
                    ):
                        for variant in _code_variants(key):
                            cache[variant] = name
        except Exception:
            continue

    # 再补手工映射，仅作为缺失兜底（比如港股/ETF/临时补丁），不覆盖基础表。
    for code, name in STOCK_NAMES.items():
        for variant in _code_variants(code):
            cache.setdefault(variant, name)

    return cache


def stock_name(code: str, fallback_to_code: bool = True) -> str:
    """将代码转为简称；优先手工缓存，其次本地基础表；缺失时可选择不回退代码。"""
    global STOCK_NAME_CACHE
    if STOCK_NAME_CACHE is None:
        STOCK_NAME_CACHE = _load_stock_name_cache()

    for variant in _code_variants(code):
        name = STOCK_NAME_CACHE.get(variant)
        if name:
            return name
    return code if fallback_to_code else "—"


def unique_strategy_ids(entries: list[dict]) -> list[str]:
    """提取并去重策略来源，保留原始出现顺序。"""
    strategies: list[str] = []
    for entry in entries:
        raw = str(entry.get("strategy") or "")
        for part in raw.split("|"):
            strategy = part.strip()
            if strategy and strategy not in strategies:
                strategies.append(strategy)
    return strategies


def format_buy_source(signal_file: str, entries: list[dict], source_generated_at: str = "") -> str:
    """格式化买入候选来源说明。"""
    if not signal_file:
        return "未知"

    strategies = unique_strategy_ids(entries)
    strategy_text = " / ".join(strategies)

    if signal_file.startswith("merged_signals_"):
        if strategy_text:
            base = f"合并信号池 {signal_file}（策略：{strategy_text}；非单一模拟盘）"
        else:
            base = f"合并信号池 {signal_file}（非单一模拟盘）"
    elif signal_file.startswith("today_stock_strategy_report"):
        if strategy_text:
            base = f"当日策略报告 {signal_file}（策略：{strategy_text}；按当前时点刷新）"
        else:
            base = f"当日策略报告 {signal_file}（按当前时点刷新）"
    else:
        if strategy_text:
            base = f"{signal_file}（策略：{strategy_text}）"
        else:
            base = signal_file

    if source_generated_at:
        return f"{base} | 更新时间：{source_generated_at}"
    return base


# ============ 1. 读取 TrendRadar 舆情 ============

def get_trendradar() -> tuple[dict, int]:
    """读取今日 TrendRadar 数据并分类"""
    today_label = today.strftime("%Y年%m月%d日")
    txt_dir = TREND_DIR / "output" / today_label / "txt"

    if not txt_dir.exists():
        return {}, 0

    txt_files = sorted(txt_dir.glob("*.txt"), key=lambda p: p.stat().st_mtime, reverse=True)
    if not txt_files:
        return {}, 0

    content = txt_files[0].read_text(encoding="utf-8")
    items = []
    current_source = None

    for line in content.split("\n"):
        line = line.strip()
        if not line:
            continue
        # 解析来源行：例如 "toutiao | 今日头条"
        if " | " in line and not line.startswith("http") and not re.match(r"^\d+\.", line):
            parts = line.split(" | ")
            if len(parts) == 2:
                current_source = parts[0].strip()
                continue
        # 解析条目行：例如 '1. "梅姨"长相... [URL:https://...]'
        if current_source:
            m = re.match(r'^\d+\.\s+(.+?)\s+\[URL:(.+?)\]$', line)
            if m:
                title = re.sub(r"<[^>]+>", "", m.group(1))
                title = html_module.unescape(title).strip()
                items.append({"title": title, "url": m.group(2), "source": current_source})

    # 财经关键词（收紧，减少噪音）
    fin_kw = [
        "股", "A股", "上证", "深证", "创业板", "科创板", "沪深",
        "美联储", "降息", "加息", "CPI", "PPI", "央行", "汇率",
        "美股", "港股", "油价", "黄金", "原油", "铜", "铝",
        "板块", "资金", "龙头", "涨跌", "涨停", "跌停",
        "牛市", "熊市", "地缘", "战争", "冲突", "制裁",
        "中美", "贸易战", "俄乌", "伊朗", "以色列", "美以",
        "财报", "业绩", "预盈", "预亏", "分红",
        "AI", "芯片", "半导体", "英伟达", "算力",
        "ETF", "指数", "大盘", "北向", "外资", "融资",
        "增持", "减持", "回购", "ST", "退市", "并购", "重组",
    ]

    fin_items = [i for i in items if sum(1 for kw in fin_kw if kw in i["title"]) >= 1]

    # 分类（互斥，每个条目只进一个桶）
    cats: dict[str, list] = {
        "地缘政治": [], "宏观经济": [], "A股市场": [],
        "板块资金": [], "大宗商品": [], "公司财报": [], "AI科技": [], "其他": [],
    }
    for item in fin_items:
        t = item["title"]
        if any(w in t for w in ["战争", "冲突", "制裁", "中东", "伊朗", "以色列",
                                  "中美", "俄乌", "俄罗斯", "普京", "关税", "胡塞",
                                  "导弹", "美以", "核设施", "袭击"]):
            cats["地缘政治"].append(item)
        elif any(w in t for w in ["美联储", "降息", "加息", "CPI", "PPI", "GDP",
                                    "央行", "通胀", "衰退", "非农", "汇率", "人民币",
                                    "美元", "美债", "债市", "加息概率"]):
            cats["宏观经济"].append(item)
        elif any(w in t for w in ["A股", "上证", "深证", "创业板", "科创板",
                                    "大盘", "指数", "涨", "跌", "涨停", "跌停",
                                    "牛市", "熊市", "两市", "成交额", "收盘"]):
            cats["A股市场"].append(item)
        elif any(w in t for w in ["板块", "概念", "龙头", "主力", "资金",
                                    "净流入", "净流出", "热点", "ETF", "外资",
                                    "北向", "融资", "融券", "概念股"]):
            cats["板块资金"].append(item)
        elif any(w in t for w in ["黄金", "白银", "铜", "铝", "原油", "天然气",
                                    "大宗商品", "油价", "商品"]):
            # 排除假阳性：标题含"睡眠/健康/养生"则不是大宗商品新闻
            if any(bad in t for bad in ["睡眠", "养生", "健康", "睡眠", "减肥", "长寿"]):
                cats["其他"].append(item)
            else:
                cats["大宗商品"].append(item)
        elif any(w in t for w in ["财报", "业绩", "营收", "利润", "分红",
                                    "回购", "增持", "减持", "预盈", "预亏", "ST", "退市",
                                    "并购", "重组"]):
            cats["公司财报"].append(item)
        elif any(w in t for w in ["AI", "人工智能", "芯片", "半导体", "英伟达",
                                    "算力", "大模型", "科技股", "半导体"]):
            cats["AI科技"].append(item)
        else:
            cats["其他"].append(item)

    return cats, len(items)


# ============ 2. 读取微博监控最新内容 ============

def get_weibo() -> dict:
    """读取微博监控最新推送内容"""
    result = {"status": "inactive", "posts": [], "last_time": None}

    if not WEIBO_LOG.exists():
        return result

    # 读最近 100 行日志，找最新有内容的记录
    lines = WEIBO_LOG.read_text(encoding="utf-8").split("\n")
    recent = lines[-100:] if len(lines) > 100 else lines

    for line in reversed(recent):
        line = line.strip()
        if "开始检测微博" in line or "没有新微博" in line:
            # 提取时间
            m = re.match(r"\[(.+?)\]", line)
            if m:
                result["last_time"] = m.group(1)
            break

    # 尝试读取 Skill 配置看监控的是谁
    if WEIBO_SKILL.exists():
        content = WEIBO_SKILL.read_text(encoding="utf-8")
        m = re.search(r"uid[：:]\s*(\d+)", content)
        if m:
            result["monitored_uid"] = m.group(1)
        m2 = re.search(r"监控对象[：:]\s*(.+)", content)
        if m2:
            result["account"] = m2.group(1).strip()

    # 读 state 文件获取最新 post_id
    state_file = WEIBO_DIR / "state" / "last_post_id.json"
    if state_file.exists():
        try:
            state = json.loads(state_file.read_text())
            result["last_post_id"] = state.get("last_post_id", "?")
            result["status"] = "active"
        except Exception:
            pass

    return result


# ============ 3. 读取量化信号（merged CSV）=============

def get_quant_signals() -> dict:
    """读取最新量化信号；优先使用当天策略报告，确保随推送时间刷新。"""
    result = {
        "audit_status": "unknown", "annual_return": None,
        "max_drawdown": None, "sharpe": None,
        "paper_date_tag": None, "paper_ready": False,
        "signals": [], "top_buy": [], "top_sell": [],
        "signal_file": "", "signal_generated_at": "",
        "buy_candidates_count": None, "research_buy_candidates_count": None,
    }

    reports = QUANT_ROOT / "research" / "reports"
    signals_dir = QUANT_ROOT / "signals" / "merged"

    # 找最新审计 JSON
    audit_files = sorted(reports.glob("daily_strategy_audit_*.md"),
                         key=lambda p: p.stat().st_mtime, reverse=True)
    if audit_files:
        try:
            content = audit_files[0].read_text(encoding="utf-8")
            # 解析 markdown 格式的审计（处理中文标点和不可见字符）
            m = re.search(r"总体状态[：:\s]*[`'（）\(\)]*(\w+)", content)
            if m:
                result["audit_status"] = m.group(1)
            m = re.search(r"年化\s*([0-9.]+)%", content)
            if m:
                result["annual_return"] = float(m.group(1))
            m = re.search(r"回撤\s*([0-9.]+)%", content)
            if m:
                result["max_drawdown"] = float(m.group(1))
            m = re.search(r"夏普\s*([0-9.]+)", content)
            if m:
                result["sharpe"] = float(m.group(1))
            m = re.search(r"模拟盘日期[：:]\s*(\d+)", content)
            if m:
                result["paper_date_tag"] = m.group(1)
        except Exception:
            pass

    def _normalize_candidate_rows(rows: list[dict]) -> list[dict]:
        normalized: list[dict] = []
        for row in rows:
            code = str(row.get("ts_code") or row.get("code") or "").strip()
            if not code:
                continue
            normalized.append({
                "date": str(row.get("trade_date") or today_str),
                "code": code,
                "name": str(row.get("ai_stock_name") or row.get("name") or stock_name(code)),
                "signal": str(row.get("action") or "BUY"),
                "score": float(row.get("score") or 0),
                "weight": float(row.get("target_weight") or 0),
                "strategy": str(row.get("strategy_id") or ""),
                "risk": str(row.get("risk_status") or row.get("risk_adjustment") or ""),
                "comment": str(row.get("reason") or ""),
            })
        normalized.sort(key=lambda x: x["score"], reverse=True)
        return normalized

    # 优先读取 latest 策略报告（它已经是当日最新生成的报告），不再用日期过滤
    # 仅当文件不存在时才 fallback 到 merged_signals
    strategy_report = reports / "today_stock_strategy_report_latest.json"
    if strategy_report.exists():
        try:
            data = json.loads(strategy_report.read_text(encoding="utf-8"))
            date_tag = str(data.get("date_tag") or "")
            result["signal_file"] = strategy_report.name
            result["signal_generated_at"] = str(data.get("generated_at") or "")
            result["buy_candidates_count"] = int(data.get("buy_candidates") or 0)
            result["research_buy_candidates_count"] = int(data.get("research_buy_candidates") or 0)

            current_rows = list(data.get("priority_candidates") or []) + list(data.get("guarded_candidates") or [])
            research_rows = list(data.get("research_priority_candidates") or []) + list(data.get("research_guarded_candidates") or [])
            display_rows = list(data.get("display_tech_candidates") or []) + list(data.get("display_guard_candidates") or [])

            # Deduplicate within each concatenated list (keep first occurrence = highest score due to prior sort)
            def dedup_by_code(rows):
                seen = set()
                out = []
                for r in rows:
                    code = r.get("ts_code", "") or r.get("symbol", "")
                    if code and code not in seen:
                        seen.add(code)
                        out.append(r)
                return out

            current_rows = dedup_by_code(current_rows)
            research_rows = dedup_by_code(research_rows)
            display_rows = dedup_by_code(display_rows)

            top_rows = current_rows or research_rows or display_rows
            result["top_buy"] = _normalize_candidate_rows(top_rows)[:8]
            result["top_sell"] = _normalize_candidate_rows(list(data.get("sell_candidates_list") or []))[:5]
            result["signals_source_kind"] = "today_strategy_report"
            return result
        except Exception as e:
            result["signal_error"] = str(e)

    # fallback：找最新 merged 信号 CSV（今天或昨天）
    today_csv = signals_dir / f"merged_signals_{today_short}.csv"
    yesterday = (today - timedelta(days=1)).strftime("%Y%m%d")
    yesterday_csv = signals_dir / f"merged_signals_{yesterday}.csv"

    signal_file = today_csv if today_csv.exists() else (
        yesterday_csv if yesterday_csv.exists() else None
    )

    if signal_file is None:
        all_csv = sorted(signals_dir.glob("merged_signals_*.csv"),
                         key=lambda p: p.stat().st_mtime, reverse=True)
        if all_csv:
            signal_file = all_csv[0]

    if signal_file and signal_file.exists():
        result["signal_file"] = str(signal_file.name)
        result["signal_generated_at"] = datetime.fromtimestamp(signal_file.stat().st_mtime).strftime("%Y-%m-%d %H:%M:%S")
        try:
            reader = csv.DictReader(signal_file.open(encoding="utf-8"))
            for row in reader:
                if row.get("trade_date"):
                    code = row.get("ts_code", "")
                    name = stock_name(code, fallback_to_code=False)
                    entry = {
                        "date": row.get("trade_date", ""),
                        "code": code,
                        "name": name,
                        "signal": row.get("signal_type", ""),
                        "score": float(row.get("score", 0)),
                        "weight": float(row.get("target_weight", 0)),
                        "strategy": row.get("strategy_id", ""),
                        "risk": row.get("risk_flag", ""),
                        "comment": row.get("comment", ""),
                    }
                    result["signals"].append(entry)
        except Exception as e:
            result["signal_error"] = str(e)

        buy_signals = [s for s in result["signals"] if s["signal"] == "BUY"]
        buy_signals.sort(key=lambda x: x["score"], reverse=True)
        result["top_buy"] = buy_signals[:8]
        result["top_sell"] = [s for s in result["signals"] if s["signal"] == "SELL"][:5]
        result["signals_source_kind"] = "merged_signals"

    return result


# ============ 4. 读取最新持仓 ============

def get_holdings() -> dict:
    """只读取已明确选定的真实持仓快照。"""
    rows, meta = resolve_real_holdings(include_auto=False)
    result = {"count": 0, "positions": [], "source": meta.get("selected_file", "-")}
    if not rows:
        result["error"] = meta.get("fallback_reason") or "missing_selected_real_holdings_source"
        return result

    try:
        for row in rows:
            code = row.get("ts_code") or row.get("symbol") or ""
            name = row.get("name") or stock_name(code)
            qty = row.get("qty") or row.get("quantity") or ""
            cost = row.get("cost_price") or row.get("cost") or ""
            if code:
                result["positions"].append(
                    {
                        "code": code,
                        "name": name,
                        "qty": qty,
                        "cost": cost,
                    }
                )
        result["count"] = len(result["positions"])
    except Exception as e:
        result["error"] = str(e)

    return result


# ============ 5. 读取三盘模拟账户状态 ============

def get_paper_profiles() -> dict:
    """读取三盘最新状态"""
    reports = QUANT_ROOT / "research" / "reports"
    result = {}
    for slug in ("defensive", "balanced", "aggressive"):
        profile_files = sorted(
            reports.glob(f"paper_{slug}_account_v1_latest.json"),
            key=lambda p: p.stat().st_mtime, reverse=True
        )
        if profile_files:
            try:
                data = json.loads(profile_files[0].read_text(encoding="utf-8"))
                result[slug] = {
                    "file": profile_files[0].name,
                    "positions": data.get("position_count", 0),
                    "date_tag": data.get("date_tag", "unknown"),
                }
            except Exception:
                pass
    return result


# ============ 6. 构建情报简报 ============

def build_brief(trend: dict, weibo: dict, signals: dict,
                holdings: dict, profiles: dict) -> str:
    """构建结构化情报简报"""
    now_str = datetime.now().strftime("%Y-%m-%d %H:%M")
    lines = [
        f"# A股投研情报简报",
        f"- 生成时间：{now_str}",
        "",
    ]

