def parse_time(time_str: str) -> datetime:
    """解析微博时间字符串"""
    # 格式: "Mon Mar 23 15:28:32 +0800 2026"
    try:
        return datetime.strptime(time_str, "%a %b %d %H:%M:%S +0800 %Y")
    except:
        try:
            # 格式: "2026-03-23 15:28:32"
            return datetime.strptime(time_str[:19], "%Y-%m-%d %H:%M:%S")
        except:
            return None

def is_today(dt: datetime) -> bool:
    """判断是否今天或昨天的微博"""
    if dt is None:
        return True  # 无法解析的默认保留
    now = datetime.now()
    today_start = now.replace(hour=0, minute=0, second=0, microsecond=0)
    yesterday_start = today_start - timedelta(days=1)
    return dt >= yesterday_start

